import{_ as d,o as r,c as e,a4 as a}from"./chunks/framework.E9a65_Io.js";const l=JSON.parse('{"title":"古董","description":"","frontmatter":{},"headers":[],"relativePath":"antique.md","filePath":"antique.md"}'),n={name:"antique.md"};function o(i,t,m,p,s,_){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="古董" tabindex="-1">古董 <a class="header-anchor" href="#古董" aria-label="Permalink to &quot;古董&quot;">​</a></h1><p>古董是可在世界一、世界二、水水世界和子领域一中获得的矿石等级。它被称为游戏初期&quot;最容易获得&quot;的矿石等级，因为该等级的大多数矿石稀有度不超过 200 万。</p><p>目前共有 16 种古董矿石。其中 9 种在世界一和水水世界，都是爱心形状；4 种在世界二，都是书本形状；2 种在子领域一，都是旗帜；最后一种是限时矿石，曾在六月、七月和八月期间可获得——那就是排球。</p><p>当前可获得的古董矿石按顺序如下：</p><table tabindex="0"><thead><tr><th>矿石</th><th>稀有度</th><th>位置</th></tr></thead><tbody><tr><td>💚 绿色爱心</td><td>1/750k</td><td>世界一、水水</td></tr><tr><td>💙 蓝色爱心</td><td>1/800k</td><td>世界一、水水</td></tr><tr><td>📗 绿色书本</td><td>1/854k</td><td>世界二</td></tr><tr><td>💛 黄色爱心</td><td>1/900k</td><td>世界一、水水</td></tr><tr><td>🧡 橙色爱心</td><td>1/950k</td><td>世界一、水水</td></tr><tr><td>❤️ 红色爱心</td><td>1/1m</td><td>世界一、水水</td></tr><tr><td>🇩🇿 阿尔及利亚国旗</td><td>1/1m</td><td>子领域一</td></tr><tr><td>🇸🇩 苏丹国旗</td><td>1/1.2m</td><td>子领域一</td></tr><tr><td>📕 红色书本</td><td>1/1.23m</td><td>世界二</td></tr><tr><td>💜 紫色爱心</td><td>1/1.25m</td><td>世界一、水水</td></tr><tr><td>🤎 棕色爱心</td><td>1/1.5m</td><td>世界一、水水</td></tr><tr><td>📙 橙色书本</td><td>1/1.5m</td><td>世界二</td></tr><tr><td>🖤 黑色爱心</td><td>1/1.75m</td><td>世界一、水水</td></tr><tr><td>📘 蓝色书本</td><td>1/1.9m</td><td>世界二</td></tr><tr><td>🤍 白色爱心</td><td>1/2m</td><td>世界一、水水</td></tr></tbody></table><p>目前唯一无法获得的古董是 🏐 排球，稀有度为 1/1.47m。与之前所有的古董不同，🏐 排球是唯一只能在特定地层中获得的古董。其他古董都可以在各自所在世界的任意地层中获得，但 🏐 排球不行。</p><p>🏐 排球 - 1/1.47m - 世界一 - 仙人掌地层</p><hr><p><em>由 <a href="https://the-silly-caverns.fandom.com/wiki/Antique" target="_blank" rel="noreferrer">笨猫探穴 Wiki</a> 汉化</em></p>',9)])])}const c=d(n,[["render",o]]);export{l as __pageData,c as default};
